          "text": "function makeLRU(capacity = 1000, ttlMs = 60_000) {\n  const map = new Map(); // key -> { value, expiresAt }\n\n  function get(key) {\n    const entry = map.get(key);\n    if (!entry) return undefined;\n    if (entry.expiresAt < Date.now()) { map.delete(key); return undefined; }\n    // обновляем \"свежесть\"\n    map.delete(key);\n    map.set(key, entry);\n    return entry.value;\n  }\n\n  function set(key, value) {\n    if (map.size >= capacity) {\n      const oldestKey = map.keys().next().value;\n      map.delete(oldestKey);\n    }\n    map.set(key, { value, expiresAt: Date.now() + ttlMs });\n  }\n\n  return { get, set };\n}\n\nconst cache = makeLRU(500, 10_000);\n\nasync function fetchJsonCached(url, options = {}) {\n  const key = url + ':' + JSON.stringify(options);\n  const cached = cache.get(key);\n  if (cached) return cached;\n\n  const res = await fetch(url, options);\n  if (!res.ok) throw new Error(res.statusText);\n  const data = await res.json();\n  cache.set(key, data);\n  return data;\n}\n\n(async () => {\n  console.time('first');\n  await fetchJsonCached('https://api.example.com/users?limit=50');\n  console.timeEnd('first');\n\n  console.time('cached');\n  await fetchJsonCached('https://api.example.com/users?limit=50');\n  console.timeEnd('cached');\n})();\n\n// В реальном сервисе добавьте дедупликацию одновременных запросов и стратегию инвалидации."
