console.log(fib(10)); // 55"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример 2: Количество способов набрать сумму (Coin Change, комбинации)"}]},{"type":"paragraph","content":[{"type":"text","text":"Задача: по неограниченному набору монет coins посчитать количество способов набрать сумму amount. Состояние: dp[s] — число способов набрать сумму s. База: dp[0]=1 (один способ набрать ноль — ничего не брать). Порядок: внешне — по монетам, внутренне — по сумме в возрастающем порядке, чтобы не считать перестановки как разные способы."}]},{"type":"codeBlock","content":[{"type":"text","text":"function countWays(coins, amount) {
  const dp = new Array(amount + 1).fill(0);
  dp[0] = 1;
  for (const coin of coins) {
    for (let s = coin; s <= amount; s++) {
      dp[s] += dp[s - coin];
    }
  }
  return dp[amount];
}

console.log(countWays([1, 2, 5], 5)); // 4 (1+1+1+1+1, 1+1+1+2, 1+2+2, 5)"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Выбор порядка обхода — частые паттерны"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Неограниченные предметы (unbounded, напр. coin change «кол-во способов»): внешний цикл по предметам, внутренний — по «весу/сумме» в возрастающем порядке."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"0/1 рюкзак (каждый предмет не более одного раза): внешний — по предметам, внутренний — по весу в убывающем порядке, чтобы не переиспользовать предмет в той же итерации."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Двумерные DP (LCS, редакт. расстояние): заполняем матрицу по строкам/столбцам, начиная с базовой строки/столбца."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Оптимизация памяти (rolling array)"}]},{"type":"paragraph","content":[{"type":"text","text":"Если переход использует только предыдущую строку/столбец, можно хранить лишь её. Пример: 0/1 рюкзак с одной строкой и обратным обходом веса:"}]},{"type":"codeBlock","content":[{"type":"text","text":"function knap01(weights, values, W) {
  const dp = new Array(W + 1).fill(0);
  for (let i = 0; i < weights.length; i++) {
    const w = weights[i], v = values[i];
    for (let cap = W; cap >= w; cap--) {
      dp[cap] = Math.max(dp[cap], dp[cap - w] + v);
    }
  }
  return dp[W];
}

console.log(knap01([2,3,4], [4,5,10], 6)); // 14 (взять предметы весов 2 и 4)"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Сложность и когда применять"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Время: O(число состояний × число переходов из каждого состояния)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: O(число состояний), часто уменьшается до O(размера одного слоя) при аккуратном порядке обхода."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Применять, когда есть DAG подзадач с естественным порядком, важно избежать рекурсии, и/или нужно вычислить не только финальный ответ, но и все промежуточные значения."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Типичные ошибки"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Неправильная инициализация баз: dp[0] для «кол-ва способов» должен быть 1, а не 0."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ошибочный порядок обхода, из-за чего используете ещё не посчитанные значения или пересчитываете состояния с переиспользованием элементов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Смещения индексов (off-by-one) в 1D/2D массивах."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Путаница между минимумами/максимумами и количеством способов — разные базы и операции (+, min, max)."}]}]}]}]}

