    {
      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "def lis_n2(a):\n    n = len(a)\n    dp = [1] * n  # dp[i] — LIS, заканчивающаяся на i\n    for i in range(n):\n        for j in range(i):\n            if a[j] < a[i]:\n                dp[i] = max(dp[i], dp[j] + 1)\n    return max(dp, default=0)"
