      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "import bisect\n\ndef lis_nlogn(a):\n    tails = []  # tails[k] — минимальный последний элемент для длины k+1\n    for x in a:\n        i = bisect.bisect_left(tails, x)\n        if i == len(tails):\n            tails.append(x)\n        else:\n            tails[i] = x\n    return len(tails)"
